<script setup>
import AppLayout from '@/Layouts/AppLayout.vue';
import { router } from '@inertiajs/vue3';
import { computed, reactive } from 'vue';
const props = defineProps({ filters: Object, resumo: Object, vendas_por_dia: Array, vendas_por_tipo: Array, vendas_bar_por_ponto: Array, caixas_por_ponto: Array, top_produtos: Array, top_categorias: Array });
const filtros = reactive({ ...props.filters });
const max = computed(() => Math.max(1, ...(props.vendas_por_dia ?? []).map((d) => Number(d.total))));
const euros = (v) => Number(v ?? 0).toFixed(2) + '€';
const filtrar = () => router.get(route('relatorios.periodo'), filtros, { preserveState: true });
const pdf = () => { window.location = route('relatorios.pdf', filtros); };
</script>
<template><AppLayout><h1 class="mb-6 text-2xl font-black">Relatório por Período</h1><form class="mb-6 grid gap-3 rounded-lg bg-white p-4 shadow-sm md:grid-cols-4" @submit.prevent="filtrar"><input v-model="filtros.data_inicio" type="date" class="rounded-md border-slate-300"><input v-model="filtros.data_fim" type="date" class="rounded-md border-slate-300"><select v-model="filtros.tipo" class="rounded-md border-slate-300"><option value="todos">Todos</option><option value="restaurante">Restaurante</option><option value="bar">Bar Conta</option><option value="bar_prepago">Bar Pré-pago</option></select><button class="rounded-md bg-slate-900 px-4 py-2 font-bold text-white">Filtrar</button></form><div class="grid gap-4 md:grid-cols-4"><div v-for="card in [['Total', resumo.total_periodo], ['Custo Estimado', resumo.custo_estimado], ['Margem Estimada', resumo.margem_estimada], ['Nº Pedidos', resumo.total_pedidos]]" :key="card[0]" class="rounded-lg bg-white p-5 shadow-sm"><div class="text-sm text-slate-500">{{ card[0] }}</div><div class="text-3xl font-black">{{ card[0] === 'Nº Pedidos' ? card[1] : euros(card[1]) }}</div><div v-if="card[0] === 'Margem Estimada'" class="mt-1 text-sm font-bold text-emerald-700">{{ Number(resumo.margem_percentagem || 0).toFixed(1) }}%</div></div></div><section class="mt-6 rounded-lg bg-white p-5 shadow-sm"><div class="mb-3 flex justify-between"><h2 class="font-black">Vendas por dia</h2><button type="button" class="rounded-md bg-emerald-600 px-4 py-2 font-bold text-white" @click="pdf">Exportar PDF</button></div><div class="flex h-64 items-end gap-3 overflow-x-auto"><div v-for="dia in vendas_por_dia" :key="dia.data" class="flex min-w-20 flex-1 flex-col items-center"><strong class="text-xs">{{ euros(dia.total) }}</strong><div class="w-full rounded-t bg-blue-600" :style="{ height: `${Math.max(8, Number(dia.total) / max * 210)}px` }"></div><span class="mt-2 text-xs">{{ dia.data }}</span></div></div></section><section class="mt-6 rounded-lg bg-white p-5 shadow-sm"><h2 class="mb-3 font-black">Dinheiro do Bar por ponto</h2><div v-if="!vendas_bar_por_ponto?.length" class="text-sm text-slate-500">Sem vendas de bar neste período.</div><div v-for="linha in vendas_bar_por_ponto" :key="linha.ponto" class="flex justify-between border-t py-2"><span class="font-bold">{{ linha.ponto }}</span><strong>{{ euros(linha.total) }} · {{ linha.pedidos }} pedidos · {{ Number(linha.percentagem).toFixed(1) }}%</strong></div></section><section class="mt-6 rounded-lg bg-white p-5 shadow-sm"><h2 class="mb-3 font-black">Caixa e fundo de maneio</h2><div v-if="!caixas_por_ponto?.length" class="text-sm text-slate-500">Sem caixas abertas neste período.</div><div v-for="linha in caixas_por_ponto" :key="linha.ponto" class="grid gap-2 border-t py-3 text-sm md:grid-cols-7"><strong>{{ linha.ponto }}</strong><span>Dias: {{ linha.dias_abertos }}</span><span>Fechados: {{ linha.dias_fechados }}</span><span>Fundo: {{ euros(linha.fundo_maneio) }}</span><span>Vendas: {{ euros(linha.vendas) }}</span><strong class="text-emerald-700">Esperado: {{ euros(linha.esperado_caixa) }}</strong><strong>Dif.: {{ euros(linha.diferenca) }}</strong></div></section><div class="mt-6 grid gap-6 lg:grid-cols-3"><section class="rounded-lg bg-white p-5 shadow-sm"><h2 class="mb-3 font-black">Vendas por Tipo</h2><div v-for="r in vendas_por_tipo" :key="r.tipo" class="flex justify-between border-t py-2"><span>{{ r.tipo }}</span><strong>{{ euros(r.total) }} · {{ Number(r.percentagem).toFixed(1) }}%</strong></div></section><section class="rounded-lg bg-white p-5 shadow-sm"><h2 class="mb-3 font-black">Top Produtos</h2><div v-for="p in top_produtos" :key="p.nome" class="border-t py-2 text-sm"><div class="flex justify-between gap-3"><span>{{ p.nome }} · {{ p.categoria }}</span><strong>{{ p.quantidade }} / {{ euros(p.total) }}</strong></div><div class="mt-1 flex justify-between gap-3 text-xs text-slate-500"><span>Custo {{ euros(p.custo_estimado) }}</span><strong class="text-emerald-700">Margem {{ euros(p.margem_estimada) }} · {{ Number(p.margem_percentagem || 0).toFixed(1) }}%</strong></div></div></section><section class="rounded-lg bg-white p-5 shadow-sm"><h2 class="mb-3 font-black">Por Categoria/Secção</h2><div v-for="c in top_categorias" :key="c.categoria" class="flex justify-between border-t py-2"><span>{{ c.categoria }}</span><strong>{{ euros(c.total) }}</strong></div></section></div></AppLayout></template>

